#include<bits/stdc++.h>
using namespace std;
vector<int>graph[100005];
int A[100005];
void dfs(int x,int maxi){
	if(A[x])return;
	A[x]=maxi;
	for(int i=0;i<graph[x].size();i++){
		dfs(graph[x][i],maxi);
	} 
}
int main()
{
	int n,m;
	cin>>n>>m;
	for(int i=0;i<m;i++){
		int u,v;
		cin>>u>>v;
		graph[v].push_back(u);
	}
	for(int i=n;i>=1;i--)dfs(i,i);
	for(int i=1;i<=n;i++)cout<<A[i]<<" ";
}
